  function getElaborativePrompt(q) {
    if (ELABORATIVE_INTERROGATIONS[q.id]) {
      return `Quick thought: ${ELABORATIVE_INTERROGATIONS[q.id]}`;
    }
    const topicName = q.topicTitle && q.topicTitle.toLowerCase().includes("vietnam") ? "US policy in Vietnam" : "the Civil Rights movement";
    return `Quick thought: How does this fact (${q.answer}) help explain the success or limitations of ${topicName}?`;
  }
  function getCardRubrics(q) {
    const splits = getFactSplit(q);
    const rubrics = [];
    if (q.year && q.year > 0) {
      rubrics.push({
        label: "Date/Year",
        text: String(q.year)
      });
    } else {
      const yearMatch = (q.question + " " + q.explanation).match(/\b(19\d{2})\b/);
      if (yearMatch) {
        rubrics.push({
          label: "Date/Year",
          text: yearMatch[1]
        });
      } else {
        rubrics.push({
          label: "Core Concept",
          text: q.answer
        });
      }
    }
    let contextText = splits.context || "";
    contextText = contextText.replace(/[\*_]/g, "");
    rubrics.push({
      label: "Context",
      text: contextText
    });
    let significanceText = splits.significance || "";
    significanceText = significanceText.replace(/[\*_]/g, "");
    rubrics.push({
      label: "Significance",
      text: significanceText
    });
    return rubrics;
  }

